import{j as e,h as n}from"./main-C2l5wGB_.js";import{P as o}from"./PublicShell-DJaRYFgu.js";const s={privacy:{title:"Privacy Policy",intro:"Revenue Leak Auditor stores account, workspace, billing, and customer-provided business records to provide the service.",sections:[["Data we process","Account identity, workspace membership, subscription status, imported contracts and billing records, integration metadata, findings, consent records, and security events."],["Why we process it","To authenticate users, operate audits, synchronize authorized providers, secure workspaces, provide billing, and respond to support requests."],["Service providers","Supabase provides authentication, database, server functions, and private file storage. Stripe processes product billing. Intuit and Stripe provide optional customer-authorized data. SendGrid delivers transactional email."],["Retention and deletion","Workspace owners can export data. Account deletion enters a seven-day recovery window, then customer records and private objects are permanently purged unless law requires retention."],["Your controls","You can review workspace access, revoke integrations, export records, leave workspaces, cancel billing, and request deletion from account settings."],["Restricted data","Do not upload HIPAA-regulated health information, government secrets, payment-card numbers, or other data requiring a specialized compliance agreement."]]},terms:{title:"Terms of Service",intro:"These terms govern use of Revenue Leak Auditor, operated by Marcello Africano.",sections:[["Decision support","Findings are estimates based on supplied records and confirmed terms. They are not accounting, tax, legal, collections, or financial advice. You remain responsible for review and action."],["Authorized use","You must have authority to upload records, connect providers, invite members, and process workspace data. Do not misuse the service or probe another customer’s access."],["Subscriptions","Paid subscriptions renew until cancelled. Plan changes and invoices are handled through Stripe. Access continues through the paid period after cancellation."],["Availability","The service may change, suspend abusive accounts, or require maintenance. No result is guaranteed to recover revenue."],["Liability","To the extent permitted by law, the service is provided without implied guarantees and liability is limited to fees paid during the prior twelve months."],["Termination","You may export and delete data through account settings. We may terminate accounts that violate these terms after reasonable notice when appropriate."]]},security:{title:"Security Overview",intro:"Security is designed around explicit workspace boundaries and minimal operational access.",sections:[["Access control","Supabase Auth sessions and database row-level policies restrict records to workspace members. Roles separate ownership, administration, analysis, and viewing."],["Documents and credentials","Contracts use private object storage. Provider refresh tokens are encrypted server-side and never returned to browser clients."],["Operational access","The platform-admin console shows service health and counts, not unrestricted customer financial records. Impersonation is not implemented."],["Auditability","Membership changes, billing events, synchronizations, exports, deletions, and audit runs create metadata-only operational events."],["Reporting","Report suspected security issues to [support email pending launch configuration]. Do not include live credentials or private customer documents in the initial message."],["Compliance boundary","The launch service is not represented as HIPAA, PCI DSS data-storage, SOC 2, or enterprise-regulated infrastructure."]]},contact:{title:"Contact",intro:"Customer support and sender email are the remaining operator-supplied launch settings.",sections:[["Support","The support address will appear here when SUPPORT_EMAIL is configured."],["Operator","Revenue Leak Auditor is operated by Marcello Africano."]]}};function l(){const i=new URLSearchParams(window.location.search).get("doc")||"privacy",r=s[i]||s.privacy;return e.jsx(o,{children:e.jsxs("main",{id:"main",className:"legal-page",children:[e.jsx("p",{className:"eyebrow",children:"Revenue Leak Auditor"}),e.jsx("h1",{children:r.title}),e.jsx("p",{className:"legal-intro",children:r.intro}),e.jsx("p",{className:"updated",children:"Draft for operator/legal review · Updated June 28, 2026"}),r.sections.map(([t,a])=>e.jsxs("section",{children:[e.jsx("h2",{children:t}),e.jsx("p",{children:a})]},t)),e.jsx("a",{className:"button secondary",href:n("marketing"),children:"Return home"})]})})}export{l as LegalPage};
